diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index f9155cc66031..c3133a4f3867 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -2869,6 +2869,49 @@ Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
     }
   }

+  // smin(X+C, Y) - smin(X, Y) --> X+C < Y ? C : 0, when C is positive and small
+  // smin(X+1, Y) - smin(X, Y) --> X < Y ? 1 : 0
+  {
+    Value *Y_val, *Add_val, *X_val;
+    ConstantInt *C_val;
+    // Op0 = smin(Y, X+C) or smin(X+C, Y), Op1 = smin(X, Y)
+    if (match(Op0, m_OneUse(m_c_SMin(m_Value(Y_val), m_Value(Add_val)))) &&
+        match(Add_val, m_c_Add(m_Value(X_val), m_ConstantInt(C_val)))) {
+      if (!C_val->isNegative() && !C_val->isZero() && C_val->getSExtValue() <= 256) {
+        // Check that Op1 = smin(X, Y)
+        if (match(Op1, m_OneUse(m_c_SMin(m_Specific(X_val), m_Specific(Y_val))))) {
+          Value *Cmp = Builder.CreateICmpSLT(X_val, Y_val);
+          Value *Select = Builder.CreateSelect(Cmp, C_val, ConstantInt::get(C_val->getType(), 0));
+          return replaceInstUsesWith(I, Select);
+        }
+        // Check that Op1 = smin(Y, X)
+        if (match(Op1, m_OneUse(m_c_SMin(m_Specific(Y_val), m_Specific(X_val))))) {
+          Value *Cmp = Builder.CreateICmpSLT(X_val, Y_val);
+          Value *Select = Builder.CreateSelect(Cmp, C_val, ConstantInt::get(C_val->getType(), 0));
+          return replaceInstUsesWith(I, Select);
+        }
+      }
+    }
+    // Also try: Op0 = smin(X+C, Y)
+    if (match(Op0, m_OneUse(m_c_SMin(m_Value(Add_val), m_Value(Y_val)))) &&
+        match(Add_val, m_c_Add(m_Value(X_val), m_ConstantInt(C_val)))) {
+      if (!C_val->isNegative() && !C_val->isZero() && C_val->getSExtValue() <= 256) {
+        // Check that Op1 = smin(X, Y)
+        if (match(Op1, m_OneUse(m_c_SMin(m_Specific(X_val), m_Specific(Y_val))))) {
+          Value *Cmp = Builder.CreateICmpSLT(X_val, Y_val);
+          Value *Select = Builder.CreateSelect(Cmp, C_val, ConstantInt::get(C_val->getType(), 0));
+          return replaceInstUsesWith(I, Select);
+        }
+        // Check that Op1 = smin(Y, X)
+        if (match(Op1, m_OneUse(m_c_SMin(m_Specific(Y_val), m_Specific(X_val))))) {
+          Value *Cmp = Builder.CreateICmpSLT(X_val, Y_val);
+          Value *Select = Builder.CreateSelect(Cmp, C_val, ConstantInt::get(C_val->getType(), 0));
+          return replaceInstUsesWith(I, Select);
+        }
+      }
+    }
+  }
+
   if (Instruction *Res = foldBinOpOfSelectAndCastOfSelectCondition(I))
     return Res;

