  // smin(X+C, Y) - smin(X, Y) --> X+C < Y ? C : 0, when C is positive and small
  // smin(X+1, Y) - smin(X, Y) --> X < Y ? 1 : 0
  if (match(Op0, m_OneUse(m_c_SMin(m_Value(Y), m_c_Add(m_Specific(Y2), m_PositiveConstant(C))))) &&
      match(Op1, m_OneUse(m_c_SMin(m_Specific(Y), m_Specific(Y2))))) {
    // smin(Y2+C, Y) - smin(Y2, Y) --> Y2 < Y ? C : 0
    ConstantInt *CI = dyn_cast<ConstantInt>(C);
    if (CI && CI->getSExtValue() > 0 && CI->getSExtValue() <= 256) {
      Value *Cmp = Builder.CreateICmpSLT(Y2, Y);
      Value *Select = Builder.CreateSelect(Cmp, C, ConstantInt::get(C->getType(), 0));
      return replaceInstUsesWith(I, Select);
    }
  }
  if (match(Op0, m_OneUse(m_c_SMin(m_c_Add(m_Specific(Y2), m_PositiveConstant(C)), m_Value(Y)))) &&
      match(Op1, m_OneUse(m_c_SMin(m_Specific(Y2), m_Specific(Y))))) {
    // smin(Y2+C, Y) - smin(Y2, Y) --> Y2 < Y ? C : 0
    ConstantInt *CI = dyn_cast<ConstantInt>(C);
    if (CI && CI->getSExtValue() > 0 && CI->getSExtValue() <= 256) {
      Value *Cmp = Builder.CreateICmpSLT(Y2, Y);
      Value *Select = Builder.CreateSelect(Cmp, C, ConstantInt::get(C->getType(), 0));
      return replaceInstUsesWith(I, Select);
    }
